'use server'

import { erpFetch } from '@/lib/erp-api'
import { revalidatePath } from 'next/cache'

/**
 * Phase 3 of the multi-dim attribute scoping feature.
 *
 * Operator review wizard for the auto-suggested scopes generated by
 * scanning observed product usage on the backend.
 *
 *   GET /api/inventory/product-attributes/scope-suggestions/?value_ids=…
 *   → list of suggestion dicts (see scope_suggester.py docstring)
 *
 *   POST /api/inventory/product-attributes/<id>/apply-scope/
 *   body: { add_categories: [...], add_countries: [...], add_brands: [...] }
 *   → diff dict describing what was added
 */

type ScopeRef = { id: number; name: string }

export type ScopeSuggestion = {
    value_id: number
    value_name: string
    group_id: number
    group_name: string
    product_count: number
    current_scope: { categories: ScopeRef[]; countries: ScopeRef[]; brands: ScopeRef[] }
    suggested_scope: { categories: ScopeRef[]; countries: ScopeRef[]; brands: ScopeRef[] }
    confidence: { categories: number; countries: number; brands: number }
}

export async function listScopeSuggestions(valueIds?: number[]): Promise<ScopeSuggestion[]> {
    const qs = valueIds && valueIds.length ? `?value_ids=${valueIds.join(',')}` : ''
    try {
        const r = await erpFetch(`inventory/product-attributes/scope-suggestions/${qs}`)
        return Array.isArray(r) ? r : []
    } catch (e) {
        console.warn('[scope-suggestions] list failed', e)
        return []
    }
}

export async function applyScopeSuggestion(
    valueId: number,
    add: { categories?: number[]; countries?: number[]; brands?: number[] },
): Promise<{ success: boolean; diff?: any; message?: string }> {
    try {
        const r = await erpFetch(`inventory/product-attributes/${valueId}/apply-scope/`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                add_categories: add.categories || [],
                add_countries:  add.countries  || [],
                add_brands:     add.brands     || [],
            }),
        })
        revalidatePath('/inventory/attributes')
        return { success: true, diff: r }
    } catch (e: any) {
        return { success: false, message: e?.message || 'Apply failed' }
    }
}
